/*------------------/-------------------/-------------------/------------------/
 * @brief   生成1024点的正弦波模拟数据
 * @param   none
 * @return  none.
 * @note    none
/-------------------/-------------------/-------------------/-----------------*/
static void generate_sine_wave(uint8_t data[1024])
{
    const double PI = 3.14159265358979323846;
    for (int i = 0; i < 1024; i++)
    {
        // 生成0-255范围内的正弦波数据
        double value = sin(2.0 * PI * i / 1024.0);  // -1.0到1.0
        data[i] = (uint8_t)((value + 1.0) * 127.5); // 映射到0-255
    }
}

/*------------------/-------------------/-------------------/------------------/
 * @brief   数据打印
 * @param   none
 * @return  none.
 * @note    none
/-------------------/-------------------/-------------------/-----------------*/
static void uart_data_process(uint8_t *data, uint16_t len)
{
    rt_kprintf("UART RX [%d bytes]: ", len);
    for (int i = 0; i < len; i++)
    {
        rt_kprintf("%02X ", data[i]);
    }
    rt_kprintf("\n");
}

